import { Assets, Texture } from 'pixi.js';
import { useTick } from '@pixi/react';

function ClickableSprite({ id, x, y, tint, onClick }) {
  const ref = useRef(null);
  const [texture, setTexture] = useState(Texture.EMPTY);
  const [hovered, setHovered] = useState(false);
  const clicks = useRef(0);
  const time = useRef(Math.random() * Math.PI * 2);

  useEffect(() => {
    if (texture === Texture.EMPTY) {
      Assets.load('https://pixijs.com/assets/bunny.png').then(setTexture);
    }
  }, [texture]);

  useTick((t) => {
    if (!ref.current) return;
    time.current += t.deltaTime * 0.03;
    ref.current.rotation = Math.sin(time.current) * 0.15;
  });

  return (
    <pixiSprite
      ref={ref}
      texture={texture}
      anchor={0.5}
      x={x}
      y={y}
      tint={tint}
      scale={hovered ? 2.2 : 1.8}
      eventMode="static"
      cursor="pointer"
      onPointerOver={() => setHovered(true)}
      onPointerOut={() => setHovered(false)}
      onClick={() => {
        clicks.current += 1;
        onClick({ id, x, y, clicks: clicks.current });
      }}
    />
  );
}

function StatusBar({ spriteCount, totalClicks, lastClicked }) {
  return (
    <div className="px-6 py-4 bg-zinc-900/50 border-t border-zinc-800/50 flex items-center gap-6 flex-wrap">
      <Stat label="Sprites">
        <span className="text-sm font-mono text-cyan-400">{spriteCount}</span>
      </Stat>
      <Stat label="Total clicks">
        <span className="text-sm font-mono text-emerald-400">{totalClicks}</span>
      </Stat>
      <Stat label="Last clicked">
        <span className="text-sm font-mono text-zinc-300">{lastClicked || '\u2014'}</span>
      </Stat>
    </div>
  );
}

