import { Sprite } from 'pixi.js';
import { Application, extend } from '@pixi/react';
extend({ Sprite });

function App() {
  const { data, send } = useNodeRed();
  const [sprites, setSprites] = useState([]);
  const [totalClicks, setTotalClicks] = useState(0);
  const [lastClicked, setLastClicked] = useState(null);
  const idRef = useRef(0);

  useEffect(() => {
    if (!data) return;
    setSprites(prev => {
      const next = [...prev, {
        id: idRef.current++,
        x: 40 + Math.random() * 520,
        y: 40 + Math.random() * 320,
        tint: data.tint || 0x22d3ee
      }];
      return next.length > 12 ? next.slice(-12) : next;
    });
  }, [data]);

  const handleClick = useCallback((info) => {
    setTotalClicks(c => c + 1);
    setLastClicked('#' + info.id);
    send({
      action: 'clicked',
      spriteId: info.id,
      x: Math.round(info.x),
      y: Math.round(info.y),
      spriteClicks: info.clicks,
      timestamp: Date.now()
    }, 'pixi/click');
  }, [send]);

  return (
    <Page>
      <Header title="fromcubes Pixi" subtitle="click the bunnies" />
      <div className="flex-1 flex items-center justify-center p-6">
        <div className="rounded-xl overflow-hidden border border-zinc-800">
          <Application width={600} height={400} background={0x18181b} antialias>
            {sprites.map(s => (
              <ClickableSprite key={s.id} {...s} onClick={handleClick} />
            ))}
          </Application>
        </div>
      </div>
      <StatusBar spriteCount={sprites.length} totalClicks={totalClicks} lastClicked={lastClicked} />
    </Page>
  );
}
